#pragma once

#include <cuda_runtime.h>
#include <curand_kernel.h>
#include <stdint.h>
#include <torch/extension.h>

// Constants
#define VOCAB_SIZE 128256

// Maximum top-k we'll handle efficiently
#define MAX_TOP_K 4096

// Host function declaration (wrapper for kernel launches)
void run_sampling_kernel(
    const float* d_probs,
    const int* d_top_k,
    const float* d_top_p,
    int64_t* d_samples,
    int batch_size,
    int vocab_size,
    cudaStream_t stream
);

#include "kernel.h"
#include <device_launch_parameters.h>
#include <curand.h>
#include <algorithm>

// Kernel for initializing curand states
__global__ void init_curand_kernel(
    curandState* states,
    unsigned long long seed,
    int batch_size
) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < batch_size) {
        curand_init(seed, idx, 0, &states[idx]);
    }
}

// Device function to find top-k indices and probabilities using selection algorithm
// Optimized for large vocab_size with reduced register usage
__device__ void find_top_k(
    const float* probs,
    int vocab_size,
    int k,
    int* indices,
    float* values
) {
    // Initialize with first k elements
    int init_k = (k < vocab_size) ? k : vocab_size;
    for (int i = 0; i < init_k; i++) {
        indices[i] = i;
        values[i] = probs[i];
    }

    // For remaining elements, maintain top-k using minimum tracking
    for (int i = init_k; i < vocab_size; i++) {
        float prob = probs[i];

        // Find minimum in current top-k (optimized with early exit)
        int min_idx = 0;
        float min_val = values[0];
        for (int j = 1; j < init_k; j++) {
            if (values[j] < min_val) {
                min_val = values[j];
                min_idx = j;
            }
        }

        // If current prob is larger than min, replace
        if (prob > min_val) {
            values[min_idx] = prob;
            indices[min_idx] = i;
        }
    }

    // Sort the top-k by probability (descending) using insertion sort
    for (int i = 1; i < init_k; i++) {
        int j = i;
        while (j > 0 && values[j] > values[j - 1]) {
            float tmp_val = values[j];
            values[j] = values[j - 1];
            values[j - 1] = tmp_val;

            int tmp_idx = indices[j];
            indices[j] = indices[j - 1];
            indices[j - 1] = tmp_idx;

            j--;
        }
    }
}

// Kernel for top-k/top-p sampling per row
__global__ void top_k_top_p_sampling_kernel(
    const float* __restrict__ probs,
    const int* __restrict__ top_k,
    const float* __restrict__ top_p,
    int64_t* __restrict__ samples,
    curandState* __restrict__ states,
    int batch_size,
    int vocab_size
) {
    int batch_idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (batch_idx >= batch_size) return;

    // Pointer to current row
    const float* row_probs = probs + batch_idx * vocab_size;

    int k = top_k[batch_idx];
    float p = top_p[batch_idx];

    // Determine valid k (match reference implementation)
    int valid_k = k;
    if (valid_k <= 0) valid_k = vocab_size;
    if (valid_k > vocab_size) valid_k = vocab_size;

    // Use local arrays for top-k storage
    // Note: For A800, we use shared memory for large arrays if needed
    int indices[MAX_TOP_K];
    float values[MAX_TOP_K];

    // Find top-k
    find_top_k(row_probs, vocab_size, valid_k, indices, values);

    // Calculate sum of top-k probabilities for renormalization
    float sum_k = 0.0f;
    for (int i = 0; i < valid_k; i++) {
        sum_k += values[i];
    }

    // Avoid division by zero
    if (sum_k == 0.0f) {
        samples[batch_idx] = static_cast<int64_t>(indices[0]);
        return;
    }

    // Apply top-p filtering (match reference implementation logic)
    int valid_p = valid_k;
    float cumsum_p = 0.0f;

    if (p <= 0.0f) {
        // When p <= 0, just take argmax
        samples[batch_idx] = static_cast<int64_t>(indices[0]);
        return;
    }

    if (p < 1.0f) {
        // Calculate cumulative probability for top-p filtering
        for (int i = 0; i < valid_k; i++) {
            cumsum_p += values[i] / sum_k;
            if (cumsum_p > p) {
                valid_p = i + 1;
                break;
            }
        }
    }

    // Renormalize the valid_p probabilities
    float sum_p = 0.0f;
    for (int i = 0; i < valid_p; i++) {
        sum_p += values[i] / sum_k;
    }

    // Avoid division by zero
    if (sum_p == 0.0f) {
        samples[batch_idx] = static_cast<int64_t>(indices[0]);
        return;
    }

    // Sample from the filtered distribution
    curandState* state = &states[batch_idx];
    float r = curand_uniform(state);

    float cumsum_sample = 0.0f;
    int selected_idx = valid_p - 1;

    for (int i = 0; i < valid_p; i++) {
        float prob = (values[i] / sum_k) / sum_p;
        cumsum_sample += prob;
        if (cumsum_sample > r) {
            selected_idx = i;
            break;
        }
    }

    // Retrieve the original index
    samples[batch_idx] = static_cast<int64_t>(indices[selected_idx]);
}

// Host function wrapper for kernel launches
void run_sampling_kernel(
    const float* d_probs,
    const int* d_top_k,
    const float* d_top_p,
    int64_t* d_samples,
    int batch_size,
    int vocab_size,
    cudaStream_t stream
) {
    // Allocate curand states with error checking
    curandState* d_states = nullptr;
    cudaError_t err = cudaMalloc(&d_states, batch_size * sizeof(curandState));
    if (err != cudaSuccess) {
        throw std::runtime_error(std::string("cudaMalloc for curand states failed: ") + cudaGetErrorString(err));
    }

    // Initialize states with appropriate block/thread configuration
    int threads = 256;
    int blocks = (batch_size + threads - 1) / threads;
    init_curand_kernel<<<blocks, threads, 0, stream>>>(d_states, 12345ULL, batch_size);

    err = cudaGetLastError();
    if (err != cudaSuccess) {
        cudaFree(d_states);
        throw std::runtime_error(std::string("init_curand_kernel failed: ") + cudaGetErrorString(err));
    }

    // Launch sampling kernel with optimized configuration for A800
    int sampling_threads = 256;
    int sampling_blocks = (batch_size + sampling_threads - 1) / sampling_threads;

    // Limit blocks to avoid excessive launch overhead
    if (sampling_blocks > 1024) {
        sampling_blocks = 1024;
    }

    top_k_top_p_sampling_kernel<<<sampling_blocks, sampling_threads, 0, stream>>>(
        d_probs,
        d_top_k,
        d_top_p,
        d_samples,
        d_states,
        batch_size,
        vocab_size
    );

    err = cudaGetLastError();
    if (err != cudaSuccess) {
        cudaFree(d_states);
        throw std::runtime_error(std::string("top_k_top_p_sampling_kernel failed: ") + cudaGetErrorString(err));
    }

    // Cleanup
    cudaFree(d_states);
}

#include <torch/extension.h>
#include <cuda_runtime.h>
#include "kernel.h"

#include <vector>
#include <iostream>

torch::Tensor run(
    torch::Tensor probs,
    torch::Tensor top_k,
    torch::Tensor top_p,
    torch::Tensor samples
) {
    // Validate inputs
    TORCH_CHECK(probs.device().is_cuda(), "probs must be on CUDA device");
    TORCH_CHECK(top_k.device().is_cuda(), "top_k must be on CUDA device");
    TORCH_CHECK(top_p.device().is_cuda(), "top_p must be on CUDA device");
    TORCH_CHECK(samples.device().is_cuda(), "samples must be on CUDA device");
    TORCH_CHECK(probs.dtype() == torch::kFloat32, "probs must be float32");
    TORCH_CHECK(top_k.dtype() == torch::kInt32, "top_k must be int32");
    TORCH_CHECK(top_p.dtype() == torch::kFloat32, "top_p must be float32");
    TORCH_CHECK(samples.dtype() == torch::kInt64, "samples must be int64");
    TORCH_CHECK(probs.size(1) == VOCAB_SIZE, "vocab_size must be 128256");
    TORCH_CHECK(top_k.size(0) == probs.size(0), "top_k batch size must match probs batch size");
    TORCH_CHECK(top_p.size(0) == probs.size(0), "top_p batch size must match probs batch size");
    TORCH_CHECK(samples.size(0) == probs.size(0), "samples batch size must match probs batch size");

    int batch_size = probs.size(0);
    int vocab_size = VOCAB_SIZE;

    // Ensure tensors are contiguous
    probs = probs.contiguous();
    top_k = top_k.contiguous();
    top_p = top_p.contiguous();
    samples = samples.contiguous();

    // Get raw pointers
    const float* d_probs = probs.data_ptr<float>();
    const int* d_top_k = top_k.data_ptr<int>();
    const float* d_top_p = top_p.data_ptr<float>();
    int64_t* d_samples = samples.data_ptr<int64_t>();

    // Get default CUDA stream
    cudaStream_t stream = 0;

    // Call the kernel wrapper function
    run_sampling_kernel(
        d_probs,
        d_top_k,
        d_top_p,
        d_samples,
        batch_size,
        vocab_size,
        stream
    );

    // Synchronize to ensure completion
    cudaDeviceSynchronize();

    return samples;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "Top-K Top-P Sampling Kernel");
}
